import java.util.*;

public class AutoboxDemo {
    public static void main(String[] args) {
        // Autoboxing: int -> Integer
        Integer a = 42;           // same as: Integer a = Integer.valueOf(42);
        ArrayList<Integer> list = new ArrayList<>();
        list.add(5);              // autoboxes int 5 to Integer(5)
        list.add(10);

        // Unboxing: Integer -> int
        int sum = 0;
        for (Integer x : list) {
            sum += x;             // unboxes Integer to int for addition
        }
        System.out.println(sum); // 15

        // Unboxing in arithmetic
        Integer x = 100;
        Integer y = 200;
        int result = x + y;      // unboxes both, adds, stores in int
        System.out.println(result); // 300

        // NullPointerException from unboxing null!
        Integer n = null;
        // int bad = n;          // RUNTIME: NullPointerException
    }
}

public class IntegerTrap {
    public static void main(String[] args) {
        Integer a = 127;
        Integer b = 127;
        System.out.println(a == b);      // true  (cached range)
        System.out.println(a.equals(b)); // true

        Integer c = 128;
        Integer d = 128;
        System.out.println(c == d);      // FALSE (outside cache: new objects)
        System.out.println(c.equals(d)); // true  (always use this!)

        // Safe comparison using primitives
        int x = c;  // unbox
        int y = d;  // unbox
        System.out.println(x == y); // true (primitive == is always safe)
    }
}

import java.util.*;

public class WhyGenerics {
    public static void main(String[] args) {
        // PRE-GENERICS (Java 1.4 style) — AVOID
        ArrayList rawList = new ArrayList();
        rawList.add("hello");
        rawList.add(42);  // No compile error, but dangerous!
        String s = (String) rawList.get(1); // RUNTIME: ClassCastException!

        // WITH GENERICS — type-safe
        ArrayList<String> typedList = new ArrayList<>();
        typedList.add("hello");
        // typedList.add(42); // COMPILE ERROR — caught early!
        String safe = typedList.get(0);  // No cast needed
        System.out.println(safe); // hello
    }
}

public class GenericsDemo {

    // Single type parameter
    static class Box<T> {
        private T value;

        public Box(T value) {
            this.value = value;
        }

        public T getValue() {
            return value;
        }

        public void setValue(T value) {
            this.value = value;
        }

        @Override
        public String toString() {
            return "Box[" + value + "]";
        }
    }

    // Two type parameters
    static class Pair<K, V> {
        K key;
        V value;

        Pair(K key, V value) {
            this.key = key;
            this.value = value;
        }

        @Override
        public String toString() {
            return key + "=" + value;
        }
    }

    public static void main(String[] args) {
        Box<Integer> intBox = new Box<>(42);
        Box<String> strBox = new Box<>("hello");
        System.out.println(intBox.getValue()); // 42
        System.out.println(strBox);            // Box[hello]

        Pair<String, Integer> p = new Pair<>("Alice", 95);
        System.out.println(p); // Alice=95
    }
}

import java.util.*;

public class GenericMethods {

    // Generic method to swap two elements in a list
    public static <T> void swap(List<T> list, int i, int j) {
        T temp = list.get(i);
        list.set(i, list.get(j));
        list.set(j, temp);
    }

    // Generic method to print an array
    public static <T> void printArray(T[] arr) {
        for (T item : arr) {
            System.out.print(item + " ");
        }
        System.out.println();
    }

    // Generic method to find maximum
    public static <T extends Comparable<T>> T findMax(T a, T b) {
        return a.compareTo(b) >= 0 ? a : b;
    }

    public static void main(String[] args) {
        ArrayList<Integer> list = new ArrayList<>(Arrays.asList(1, 2, 3, 4));
        swap(list, 0, 3);
        System.out.println(list); // [4, 2, 3, 1]

        Integer[] nums = {5, 10, 3};
        printArray(nums); // 5 10 3

        System.out.println(findMax("apple", "banana")); // banana
        System.out.println(findMax(42, 17));             // 42
    }
}

import java.util.*;

public class BoundedGenerics {

    // T must implement Comparable — lets us use compareTo()
    public static <T extends Comparable<T>> T min(T a, T b) {
        return a.compareTo(b) <= 0 ? a : b;
    }

    // Wildcard: accepts List of any type
    public static void printList(List<?> list) {
        for (Object o : list) System.out.print(o + " ");
        System.out.println();
    }

    // Upper bounded wildcard: List of Number or subclass
    public static double sumList(List<? extends Number> list) {
        double total = 0;
        for (Number n : list) total += n.doubleValue();
        return total;
    }

    public static void main(String[] args) {
        System.out.println(min(3, 7));         // 3
        System.out.println(min("cat", "bat")); // bat

        List<Integer> ints = Arrays.asList(1, 2, 3);
        List<Double> dbls = Arrays.asList(1.5, 2.5);
        printList(ints);           // 1 2 3
        System.out.println(sumList(ints)); // 6.0
        System.out.println(sumList(dbls)); // 4.0
    }
}

